text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 한다."
      },
      {
        "item": "패키지명 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara가 제안한 smoke-theme-pack.mjs에서 packageName 불일치를 무시하는 변경은 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개는 내부 스트레치 목표였지만 최종 결정은 아니었다."
      },
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토하자는 제안이 있었지만 담당자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "item": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 여부는 미결정이다."
      }
    ],
    "non_decisions": [
      {
        "item": "고객명이나 외부 파트너는 특정되지 않았다."
      },
      {
        "item": "README 설치 단계 검토의 담당자는 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인에는 정확한 마감 시각이 없었다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 재실행 결과를 확인한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계가 최신인지 점검한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "추가 소유자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "이 픽스처에 없는 고객명, 예산, 보안, 장애, 법무, 소유자, 마감일은 만들지 않는다.",
    "Wednesday는 내부 스트레치 목표로만 취급하고, 최종 공개 일정으로 승격하지 않는다.",
    "미결정 사항은 결정된 것처럼 쓰지 않는다.",
    "거절된 제안은 실행 계획으로 바꾸지 않는다.",
    "확인된 사실과 추정은 분리해서 적는다."
  ]
}
